px\",\"top\":\"70\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false},\"_animation\":\"fadeInDown\",\"animation_duration\":\"slow\"},\"elements\":[],\"widgetType\":\"heading\"},{\"id\":\"a54121f\",\"elType\":\"container\",\"settings\":{\"container_type\":\"grid\",\"presetTitle\":\"Grid\",\"presetIcon\":\"eicon-container-grid\",\"content_width\":\"full\",\"grid_columns_grid\":{\"unit\":\"fr\",\"size\":2,\"sizes\":[]},\"grid_rows_grid\":{\"unit\":\"fr\",\"size\":1,\"sizes\":[]},\"margin\":{\"unit\":\"px\",\"top\":\"-220\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false}},\"elements\":[{\"id\":\"f2f59e1\",\"elType\":\"container\",\"settings\":{\"container_type\":\"grid\",\"presetTitle\":\"Grid\",\"presetIcon\":\"eicon-container-grid\",\"content_width\":\"full\",\"grid_columns_grid\":{\"unit\":\"fr\",\"size\":2,\"sizes\":[]},\"grid_rows_grid\":{\"unit\":\"fr\",\"size\":1,\"sizes\":[]}},\"elements\":[{\"id\":\"4cc6dc6\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/localhost\\/KOIPOND\\/WORDPRESS\\/wp-content\\/uploads\\/2025\\/04\\/gambar1.png\",\"id\":139,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"},\"_animation\":\"fadeInLeft\",\"animation_duration\":\"slow\"},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"4158a92\",\"elType\":\"container\",\"settings\":{\"container_type\":\"grid\",\"presetTitle\":\"Grid\",\"presetIcon\":\"eicon-container-grid\",\"content_width\":\"full\",\"grid_columns_grid\":{\"unit\":\"fr\",\"size\":1,\"sizes\":[]}},\"elements\":[{\"id\":\"c4c1b65\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/localhost\\/KOIPOND\\/WORDPRESS\\/wp-content\\/uploads\\/2025\\/04\\/foro2.jpg\",\"id\":144,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"},\"_animation\":\"fadeInDown\",\"animation_duration\":\"slow\"},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"2f1ff1e\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/localhost\\/KOIPOND\\/WORDPRESS\\/wp-content\\/uploads\\/2025\\/04\\/foto3.jpg\",\"id\":145,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"},\"_animation\":\"fadeInUp\",\"animation_duration\":\"slow\"},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":true}],\"isInner\":true},{\"id\":\"d5b4ddd\",\"elType\":\"widget\",\"settings\":{\"title\":\"Selamat datang di Koipond \\u2014 tempat di mana keindahan, ketenangan, dan seni hidup berdampingan dalam aliran air dan warna-warni ikan koi.\\n\\nKami hadir bukan hanya sebagai penyedia jasa pembuatan kolam koi, tapi sebagai mitra bagi Anda yang ingin menghadirkan nuansa alami dan elegan ke dalam hunian, taman, atau ruang usaha Anda. Dengan pengalaman dan kecintaan kami terhadap dunia koi, kami menggabungkan estetika desain dengan sistem pemeliharaan yang modern dan efisien.\\n\\nDi Koipond, kami percaya bahwa memelihara ikan koi bukan sekadar merawat ikan, tapi juga menciptakan sebuah ekosistem kecil yang membawa kedamaian. Oleh karena itu, setiap kolam yang kami bangun dirancang dengan detail \\u2014 mulai dari sistem filtrasi, aerasi, pencahayaan, hingga pemilihan material kolam \\u2014 semua dibuat demi kenyamanan dan kesehatan koi, sekaligus memberikan pemandangan yang memanjakan mata.\\n\\nKami juga bergerak dalam bidang budidaya koi, mulai dari pemilihan indukan unggul hingga perawatan anakan koi dengan standar tinggi. Kami berkomitmen untuk menghadirkan koi yang sehat, aktif, dan memiliki nilai estetika tinggi, baik untuk keperluan hobi maupun koleksi bernilai investasi.\\n\\nTak peduli apakah Anda seorang pemula yang baru mengenal koi atau penghobi senior yang sedang mengembangkan koleksi.\\n\",\"header_size\":\"span\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Open Sans\",\"typography_font_size\":{\"unit\":\"px\",\"size\":16,\"sizes\":[]},\"_margin\":{\"unit\":\"px\",\"top\":\"10\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"heading\"}],\"isInner\":true}],\"isInner\":true}],\"isInner\":false}]'),
