Linked\":false},\"_animation\":\"fadeInLeft\",\"animation_duration\":\"slow\",\"width_mobile\":{\"unit\":\"px\",\"size\":\"\",\"sizes\":[]},\"_margin_mobile\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false},\"_animation_mobile\":\"fadeInLeft\"},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"4158a92\",\"elType\":\"container\",\"settings\":{\"container_type\":\"grid\",\"presetTitle\":\"Grid\",\"presetIcon\":\"eicon-container-grid\",\"content_width\":\"full\",\"grid_columns_grid\":{\"unit\":\"fr\",\"size\":1,\"sizes\":[]}},\"elements\":[{\"id\":\"c4c1b65\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/localhost\\/KOIPOND\\/WORDPRESS\\/wp-content\\/uploads\\/2025\\/04\\/foro2.jpg\",\"id\":144,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"},\"width_tablet\":{\"unit\":\"%\",\"size\":100,\"sizes\":[]},\"width_mobile\":{\"unit\":\"px\",\"size\":\"\",\"sizes\":[]},\"space_tablet\":{\"unit\":\"px\",\"size\":1000,\"sizes\":[]},\"space_mobile\":{\"unit\":\"px\",\"size\":\"\",\"sizes\":[]},\"_margin_tablet\":{\"unit\":\"px\",\"top\":\"480\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"-170\",\"isLinked\":false},\"_animation\":\"fadeInDown\",\"animation_duration\":\"slow\",\"_margin_mobile\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false},\"_animation_mobile\":\"fadeInRight\"},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"2f1ff1e\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/localhost\\/KOIPOND\\/WORDPRESS\\/wp-content\\/uploads\\/2025\\/04\\/foto3.jpg\",\"id\":145,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"},\"_animation\":\"fadeInUp\",\"animation_duration\":\"slow\",\"_margin_tablet\":{\"unit\":\"px\",\"top\":\"10\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"-170\",\"isLinked\":false},\"_margin_mobile\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false},\"_animation_mobile\":\"fadeInLeft\"},\"elements\":[],\"widgetType\":\"image\"}],\"isInner\":true}],\"isInner\":true},{\"id\":\"d5b4ddd\",\"elType\":\"widget\",\"settings\":{\"title\":\"Selamat datang di Koipond \\u2014 tempat di mana keindahan, ketenangan, dan seni hidup berdampingan dalam aliran air dan warna-warni ikan koi.\\n\\nKami hadir bukan hanya sebagai penyedia jasa pembuatan kolam koi, tapi sebagai mitra bagi Anda yang ingin menghadirkan nuansa alami dan elegan ke dalam hunian, taman, atau ruang usaha Anda. Dengan pengalaman dan kecintaan kami terhadap dunia koi, kami menggabungkan estetika desain dengan sistem pemeliharaan yang modern dan efisien.\\n\\nDi Koipond, kami percaya bahwa memelihara ikan koi bukan sekadar merawat ikan, tapi juga menciptakan sebuah ekosistem kecil yang membawa kedamaian. Oleh karena itu, setiap kolam yang kami bangun dirancang dengan detail \\u2014 mulai dari sistem filtrasi, aerasi, pencahayaan, hingga pemilihan material kolam \\u2014 semua dibuat demi kenyamanan dan kesehatan koi, sekaligus memberikan pemandangan yang memanjakan mata.\\n\\nKami juga bergerak dalam bidang budidaya koi, mulai dari pemilihan indukan unggul hingga perawatan anakan koi dengan standar tinggi. Kami berkomitmen untuk menghadirkan koi yang sehat, aktif, dan memiliki nilai estetika tinggi, baik untuk keperluan hobi maupun koleksi bernilai investasi.\\n\\nTak peduli apakah Anda seorang pemula yang baru mengenal koi atau penghobi senior yang sedang mengembangkan koleksi.\\n\",\"header_size\":\"span\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Open Sans\",\"typography_font_size\":{\"unit\":\"px\",\"size\":16,\"sizes\":[]},\"typography_font_size_tablet\":{\"unit\":\"px\",\"size\":16,\"sizes\":[]},\"typography_line_height_tablet\":{\"unit\":\"px\",\"size\":\"\",\"sizes\":[]},\"typography_line_height_mobile\":{\"unit\":\"px\",\"size\":\"\",\"sizes\":[]},\"typography_word_spacing_tablet\":{\"unit\":\"em\",\"size\":0,\"sizes\":[]},\"_margin\":{\"unit\":\"px\",\"top\":\"10\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false},\"align_tablet\":\"justify\",\"_margin_tablet\":{\"unit\":\"px\",\"top\":\"130\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false},\"_margin_mobile\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"heading\"}],\"isInner\":true}],\"isInner\":true}],\"isInner\":false}]'),
