eft\":\"0\",\"isLinked\":false},\"padding\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"isLinked\":false}},\"elements\":[{\"id\":\"8836280\",\"elType\":\"widget\",\"settings\":{\"image\":{\"url\":\"http:\\/\\/localhost\\/KOIPOND\\/WORDPRESS\\/wp-content\\/uploads\\/2025\\/04\\/foto3.jpg\",\"id\":145,\"size\":\"\",\"alt\":\"\",\"source\":\"library\"},\"width\":{\"unit\":\"%\",\"size\":70,\"sizes\":[]}},\"elements\":[],\"widgetType\":\"image\"},{\"id\":\"7087906\",\"elType\":\"container\",\"settings\":{\"container_type\":\"grid\",\"presetTitle\":\"Grid\",\"presetIcon\":\"eicon-container-grid\",\"content_width\":\"full\",\"grid_columns_grid\":{\"unit\":\"fr\",\"size\":1,\"sizes\":[]}},\"elements\":[{\"id\":\"b16e29c\",\"elType\":\"widget\",\"settings\":{\"title\":\"<a style=\\\"font-weight: bold;\\\">Desain & Bangun Kolam Koi Impian Anda<\\/a>\\n<p style=\\\"font-size: 20px; margin-top: 10px; color: ;\\\">\\n  Sistem filtrasi profesional, tampilan estetis maksimal\\n<\\/p>\\n\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Open Sans\",\"typography_font_size\":{\"unit\":\"px\",\"size\":29,\"sizes\":[]},\"typography_font_weight\":\"400\",\"title_color\":\"#FFFFFF\",\"_margin\":{\"unit\":\"px\",\"top\":\"0\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"-50\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"heading\"},{\"id\":\"f223cd5\",\"elType\":\"widget\",\"settings\":{\"title\":\"<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cDesain Eksklusif untuk Setiap Kolam\\u201d<\\/p>\\n<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cAhli di Bidang Filtrasi & Estetika\\u201d<\\/p>\\n<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cBisa Menangani Proyek di Seluruh Indonesia\\u201d<\\/p>\\n<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cKepuasan Pelanggan Terbukti\\u201d<\\/p>\\n<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cProyek Selesai Tepat Waktu\\u201d<\\/p>\\n<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cKolam Skala Besar & Kecil Tertangani\\u201d<\\/p>\\n<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cPelayanan Purna Jual Terjamin\\u201d<\\/p>\\n<p><a style=\\\"color: black;\\\">\\u2192 <\\/a>\\u201cBerpengalaman Sejak Tahun\\u201d 2010<\\/p>\\n\",\"header_size\":\"span\",\"typography_typography\":\"custom\",\"typography_font_family\":\"Open Sans\",\"title_color\":\"#2C2C2C\",\"_margin\":{\"unit\":\"px\",\"top\":\"-120\",\"right\":\"0\",\"bottom\":\"0\",\"left\":\"-50\",\"isLinked\":false}},\"elements\":[],\"widgetType\":\"heading\"}],\"isInner\":true}],\"isInner\":true}],\"isInner\":true}],\"isInner\":false}]'),
